// Convert HTML to Markdown, returning a [`ConversionResult`] with content, metadata, images,
// and warnings.
//
// # Arguments
//
// * `html` - The HTML string to convert
// * `options` - Optional conversion options (defaults to `ConversionOptions::default()`)
//
// # Example
//
// ```
// use html_to_markdown_rs::{convert, ConversionOptions};
//
// let html = "<h1>Hello World</h1>";
// let result = convert(html, None).unwrap();
// assert!(result.content.as_deref().unwrap_or("").contains("Hello World"));
// ```
//
// # Errors
//
// Returns an error if HTML parsing fails or if the input contains invalid UTF-8.
func Convert(html string, options *ConversionOptions) (*ConversionResult, error) {
    cHtml := C.CString(html)
    defer C.free(unsafe.Pointer(cHtml))

    jsonBytescOptions, err := json.Marshal(options)
    if err != nil {
        return nil, fmt.Errorf("failed to marshal: %w", err)
    }
    tmpStrcOptions := C.CString(string(jsonBytescOptions))
    cOptions := C.htm_conversion_options_from_json(tmpStrcOptions)
    C.free(unsafe.Pointer(tmpStrcOptions))
    defer C.htm_conversion_options_free(cOptions)

    ptr := C.htm_convert(cHtml, cOptions)
    if err := lastError(); err != nil {
        if ptr != nil {
            C.htm_conversion_result_free(ptr)
        }
        return nil, err
    }
    defer C.htm_conversion_result_free(ptr)
    return func() *ConversionResult {
	jsonPtr := C.htm_conversion_result_to_json(ptr)
	if jsonPtr == nil { return nil }
	defer C.htm_free_string(jsonPtr)
	var result ConversionResult
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil { return nil }
	return &result
}(), nil
}


// Check if any metadata extraction is enabled.
//
// Returns `true` if at least one extraction category is enabled, `false` if all are disabled.
// This is useful for early exit optimization when the application doesn't need metadata.
//
// # Returns
//
// `true` if any of the extraction flags are enabled, `false` if all are disabled.
//
// # Examples
//
// ```
// # use html_to_markdown_rs::metadata::MetadataConfig;
// // All enabled
// let config = MetadataConfig::default();
// assert!(config.any_enabled());
//
// // Selectively enabled
// let config = MetadataConfig {
// extract_headers: true,
// extract_document: false,
// extract_links: false,
// extract_images: false,
// extract_structured_data: false,
// max_structured_data_size: 1_000_000,
// };
// assert!(config.any_enabled());
//
// // All disabled
// let config = MetadataConfig {
// extract_document: false,
// extract_headers: false,
// extract_links: false,
// extract_images: false,
// extract_structured_data: false,
// max_structured_data_size: 1_000_000,
// };
// assert!(!config.any_enabled());
// ```
func (r *MetadataConfig) AnyEnabled() *bool {
    jsonBytesRecv, err := json.Marshal(r)
    if err != nil {
        panic(fmt.Sprintf("failed to marshal receiver: %v", err))
    }
    tmpStrRecv := C.CString(string(jsonBytesRecv))
    cRecv := C.htm_metadata_config_from_json(tmpStrRecv)
    C.free(unsafe.Pointer(tmpStrRecv))
    defer C.htm_metadata_config_free(cRecv)
    ptr := C.htm_metadata_config_any_enabled (cRecv)
    return func() *bool { v := ptr != 0; return &v }()
}


// Apply a partial update to this metadata configuration.
//
// Any specified fields in the update (Some values) will override the current values.
// Unspecified fields (None) are left unchanged. This allows selective modification
// of configuration without affecting unrelated settings.
//
// # Arguments
//
// * `update` - Partial metadata config update with fields to override
//
// # Examples
//
// ```
// # use html_to_markdown_rs::metadata::{MetadataConfig, MetadataConfigUpdate};
// let mut config = MetadataConfig::default();
// // config starts with all extraction enabled
//
// let update = MetadataConfigUpdate {
// extract_document: Some(false),
// extract_images: Some(false),
// // All other fields are None, so they won't change
// ..Default::default()
// };
//
// config.apply_update(update);
//
// assert!(!config.extract_document);
// assert!(!config.extract_images);
// assert!(config.extract_headers);  // Unchanged
// assert!(config.extract_links);    // Unchanged
// ```
func (r *MetadataConfig) ApplyUpdate(update MetadataConfigUpdate) {
    jsonBytescUpdate, err := json.Marshal(update)
    if err != nil {
        panic(fmt.Sprintf("failed to marshal: %v", err))
    }
    tmpStrcUpdate := C.CString(string(jsonBytescUpdate))
    cUpdate := C.htm_metadata_config_update_from_json(tmpStrcUpdate)
    C.free(unsafe.Pointer(tmpStrcUpdate))
    defer C.htm_metadata_config_update_free(cUpdate)

    jsonBytesRecv, err := json.Marshal(r)
    if err != nil {
        panic(fmt.Sprintf("failed to marshal receiver: %v", err))
    }
    tmpStrRecv := C.CString(string(jsonBytesRecv))
    cRecv := C.htm_metadata_config_from_json(tmpStrRecv)
    C.free(unsafe.Pointer(tmpStrRecv))
    defer C.htm_metadata_config_free(cRecv)
    C.htm_metadata_config_apply_update (cRecv, cUpdate)
}


